transform_js:
const seriesMap = {};
// Create some dummy scattered data around the provided sample points
rawData.rows.forEach(r => {
  if (!seriesMap[r.category]) seriesMap[r.category] = [];
  // Add the original point
  seriesMap[r.category].push([r.radius, r.angle, 15]); // [radius, angle, size]
  // Generate a cluster of random points around it for visual effect
  for(let i=0; i<15; i++) {
     const rNoise = r.radius + (Math.random() - 0.5) * 20;
     const aNoise = r.angle + (Math.random() - 0.5) * 30;
     const size = Math.random() * 10 + 5;
     if (rNoise > 0) {
        seriesMap[r.category].push([rNoise, aNoise, size]);
     }
  }
});
const seriesInfo = Object.keys(seriesMap).map(cat => {
    return {
       name: 'Group ' + cat,
       type: 'scatter',
       coordinateSystem: 'polar',
       symbolSize: function(val) { return val[2]; },
       data: seriesMap[cat],
       animationDelay: function (idx) {
         return idx * 5;
       }
    };
});
transformedData = seriesInfo;

echarts_js:
option = {
  title: {
    text: '24-hour Activity Cycle (Polar Scatter)',
    left: 'center'
  },
  legend: {
    data: transformedData.map(s => s.name),
    left: 'left',
    orient: 'vertical'
  },
  tooltip: {
    trigger: 'item',
    formatter: function(params) {
      return params.seriesName + '<br/>Distance: ' + Math.round(params.value[0]) + '<br/>Angle: ' + Math.round(params.value[1]) + '°';
    }
  },
  polar: {},
  angleAxis: {
    type: 'value',
    startAngle: 90,
    splitLine: { show: true },
    axisLabel: { formatter: '{value} °' }
  },
  radiusAxis: {
    type: 'value',
    splitLine: { show: true }
  },
  series: transformedData,
  animationDurationUpdate: 1500
};
